INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('1', '5', '1', 'Which of the following is an example of system software?', 'multiple_choice', '[\"Microsoft Word\",\"Windows 11\",\"Google Chrome\",\"Adobe Photoshop\"]', 'Windows 11', '5', 'Windows 11 is an operating system, which is a type of system software. The others are application software.', '1', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('2', '5', '2', 'What does CPU stand for?', 'multiple_choice', '[\"Central Processing Unit\",\"Computer Personal Unit\",\"Central Program Utility\",\"Computer Processing Unit\"]', 'Central Processing Unit', '5', 'CPU stands for Central Processing Unit, often called the brain of the computer.', '2', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('3', '5', '3', 'RAM is a type of volatile memory.', 'true_false', '[\"True\",\"False\"]', 'True', '5', 'RAM (Random Access Memory) is volatile, meaning it loses its contents when power is turned off.', '3', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('4', '5', '4', 'Which keyboard shortcut is used to copy selected text?', 'multiple_choice', '[\"Ctrl+V\",\"Ctrl+C\",\"Ctrl+X\",\"Ctrl+Z\"]', 'Ctrl+C', '5', 'Ctrl+C copies, Ctrl+V pastes, Ctrl+X cuts, and Ctrl+Z undoes.', '4', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('5', '5', '5', 'What is the primary function of a spreadsheet application?', 'multiple_choice', '[\"Creating presentations\",\"Managing databases\",\"Performing calculations and data analysis\",\"Editing photographs\"]', 'Performing calculations and data analysis', '5', 'Spreadsheet applications like Microsoft Excel are primarily used for calculations, data analysis, and creating charts.', '5', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('6', '5', '6', 'In Microsoft Excel, which symbol must precede every formula?', 'multiple_choice', '[\"# (hash)\",\"= (equals)\",\"@ (at)\",\"$ (dollar)\"]', '= (equals)', '5', 'Every formula in Excel must begin with the equals sign (=).', '6', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('7', '5', '7', 'A firewall protects a computer from unauthorized network access.', 'true_false', '[\"True\",\"False\"]', 'True', '5', 'A firewall monitors and controls incoming and outgoing network traffic to protect against unauthorized access.', '7', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('8', '5', '8', 'Explain the difference between hardware and software, giving two examples of each.', 'short_answer', NULL, '', '10', 'Hardware refers to physical components (e.g., keyboard, monitor). Software refers to programs and instructions (e.g., Windows OS, MS Word).', '8', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('9', '5', '9', 'Which of the following is NOT an input device?', 'multiple_choice', '[\"Mouse\",\"Keyboard\",\"Monitor\",\"Scanner\"]', 'Monitor', '5', 'A monitor is an output device that displays information. Mouse, keyboard, and scanner are input devices.', '9', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('10', '6', '1', 'What is the derivative of f(x) = 3x² + 2x - 5?', 'multiple_choice', '[\"6x + 2\",\"3x + 2\",\"6x\\u00b2 + 2\",\"6x - 5\"]', '6x + 2', '10', 'Using the power rule: d/dx(3x²) = 6x, d/dx(2x) = 2, d/dx(-5) = 0. So f\'(x) = 6x + 2.', '1', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('11', '6', '2', 'If A is a 2×3 matrix and B is a 3×4 matrix, the product AB is a 2×4 matrix.', 'true_false', '[\"True\",\"False\"]', 'True', '10', 'When multiplying matrices, the result has rows from the first matrix and columns from the second: (2×3)(3×4) = 2×4.', '2', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('12', '6', '3', 'Calculate the simple interest on MWK 500,000 at 12% per annum for 3 years.', 'multiple_choice', '[\"MWK 150,000\",\"MWK 180,000\",\"MWK 200,000\",\"MWK 160,000\"]', 'MWK 180,000', '10', 'Simple Interest = P × R × T = 500,000 × 0.12 × 3 = MWK 180,000.', '3', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('13', '6', '4', 'What is the integral of 4x³ dx?', 'multiple_choice', '[\"x\\u2074 + C\",\"12x\\u00b2 + C\",\"4x\\u2074 + C\",\"x\\u2074\\/4 + C\"]', 'x⁴ + C', '10', '∫4x³ dx = 4 × (x⁴/4) + C = x⁴ + C.', '4', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('14', '6', '5', 'In linear programming, the feasible region represents the set of all possible solutions that satisfy all constraints.', 'true_false', '[\"True\",\"False\"]', 'True', '10', 'The feasible region is the area where all constraints overlap, containing all valid solutions.', '5', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('15', '6', '6', 'Solve: If 2x + 5 = 17, what is the value of x?', 'multiple_choice', '[\"5\",\"6\",\"7\",\"8\"]', '6', '10', '2x + 5 = 17 → 2x = 12 → x = 6.', '6', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('16', '6', '7', 'A company invests MWK 1,000,000 at a compound interest rate of 10% per annum. Calculate the total amount after 2 years and explain the concept of compound interest.', 'essay', NULL, '', '20', 'Amount = P(1+r)^n = 1,000,000(1.10)² = MWK 1,210,000. Compound interest is interest earned on both the principal and accumulated interest.', '7', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('17', '6', '8', 'The determinant of a 2×2 matrix [[a,b],[c,d]] is calculated as:', 'multiple_choice', '[\"ad + bc\",\"ad - bc\",\"ac - bd\",\"ab - cd\"]', 'ad - bc', '10', 'For a 2×2 matrix [[a,b],[c,d]], the determinant = ad - bc.', '8', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('18', '6', '9', 'Define the break-even point in business and state its formula.', 'short_answer', NULL, '', '10', 'Break-even point is where total revenue equals total costs (no profit, no loss). BEP = Fixed Costs / (Selling Price per Unit - Variable Cost per Unit).', '9', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('19', '7', '1', 'The mean of the dataset {4, 8, 6, 10, 12} is:', 'multiple_choice', '[\"6\",\"7\",\"8\",\"9\"]', '8', '5', 'Mean = (4+8+6+10+12)/5 = 40/5 = 8.', '1', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('20', '7', '2', 'The median is always the same as the mean.', 'true_false', '[\"True\",\"False\"]', 'False', '5', 'The median and mean are only equal in perfectly symmetric distributions. They can differ, especially in skewed data.', '2', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('21', '7', '3', 'Which measure of dispersion is most affected by extreme values (outliers)?', 'multiple_choice', '[\"Interquartile Range\",\"Standard Deviation\",\"Range\",\"Median Absolute Deviation\"]', 'Range', '5', 'Range (max - min) is most affected by outliers since it only considers the two extreme values.', '3', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('22', '7', '4', 'If the probability of an event occurring is 0.3, what is the probability of it NOT occurring?', 'multiple_choice', '[\"0.3\",\"0.5\",\"0.7\",\"1.0\"]', '0.7', '5', 'P(not A) = 1 - P(A) = 1 - 0.3 = 0.7.', '4', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('23', '7', '5', 'The mode is the value that appears most frequently in a dataset.', 'true_false', '[\"True\",\"False\"]', 'True', '5', 'The mode is defined as the value with the highest frequency of occurrence in a dataset.', '5', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('24', '7', '6', 'Standard deviation can never be negative.', 'true_false', '[\"True\",\"False\"]', 'True', '5', 'Standard deviation is the square root of variance, which is always non-negative. Therefore, SD is always ≥ 0.', '6', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('25', '8', '1', 'Which of the following is NOT a function of management?', 'multiple_choice', '[\"Planning\",\"Organizing\",\"Manufacturing\",\"Controlling\"]', 'Manufacturing', '5', 'The four functions of management are Planning, Organizing, Leading, and Controlling. Manufacturing is an operational activity.', '1', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('26', '8', '2', 'Henri Fayol is known as the father of modern management.', 'true_false', '[\"True\",\"False\"]', 'True', '5', 'Henri Fayol developed 14 principles of management and is considered the father of modern management theory.', '2', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('27', '8', '3', 'SWOT analysis examines:', 'multiple_choice', '[\"Sales, Wages, Output, Taxes\",\"Strengths, Weaknesses, Opportunities, Threats\",\"Strategy, Workforce, Operations, Technology\",\"Supply, Wholesale, Orders, Transport\"]', 'Strengths, Weaknesses, Opportunities, Threats', '5', 'SWOT stands for Strengths, Weaknesses, Opportunities, and Threats - a strategic planning framework.', '3', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('28', '8', '4', 'Which leadership style gives employees maximum freedom in decision-making?', 'multiple_choice', '[\"Autocratic\",\"Democratic\",\"Laissez-faire\",\"Bureaucratic\"]', 'Laissez-faire', '5', 'Laissez-faire (free-rein) leadership gives subordinates complete freedom to make decisions with minimal supervision.', '4', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('29', '8', '5', 'Delegation means transferring both authority and accountability to a subordinate.', 'true_false', '[\"True\",\"False\"]', 'False', '5', 'Delegation transfers authority and responsibility, but the manager retains ultimate accountability.', '5', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('30', '8', '6', 'Maslow\'s hierarchy places self-actualization at the top.', 'true_false', '[\"True\",\"False\"]', 'True', '5', 'Maslow\'s hierarchy from bottom to top: Physiological, Safety, Social, Esteem, Self-Actualization.', '6', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('31', '8', '7', 'Explain the difference between strategic planning and operational planning. Provide examples relevant to a university setting.', 'essay', NULL, '', '15', 'Strategic planning is long-term, sets direction (e.g., university expansion plan). Operational planning is short-term, day-to-day activities (e.g., timetable scheduling).', '7', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('32', '8', '8', 'Which management theory emphasizes the importance of social relationships and employee satisfaction?', 'multiple_choice', '[\"Scientific Management\",\"Human Relations Theory\",\"Bureaucratic Management\",\"Systems Theory\"]', 'Human Relations Theory', '5', 'Human Relations Theory (Hawthorne Studies, Elton Mayo) emphasizes that social factors and employee satisfaction significantly impact productivity.', '8', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('33', '8', '9', 'Define \"span of control\" and state two factors that determine the ideal span.', 'short_answer', NULL, '', '10', 'Span of control is the number of subordinates reporting directly to a manager. Factors include: complexity of work, competence of subordinates, geographical proximity, and level of standardization.', '9', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('34', '9', '1', 'Which of the following best describes Financial Accounting I?', 'multiple_choice', '[\"Option A - Correct answer\",\"Option B - Incorrect\",\"Option C - Incorrect\",\"Option D - Incorrect\"]', 'A', '4', NULL, '0', '2026-03-01 15:08:20');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('35', '9', '2', 'What is the primary purpose of Financial Accounting I in this context?', 'multiple_choice', '[\"To achieve objective A\",\"To achieve objective B\",\"To achieve objective C\",\"To achieve objective D\"]', 'A', '4', NULL, '0', '2026-03-01 15:08:20');
